example.code:
from typing import TypedDict, Annotated from langgraph.graph import StateGraph, END from langgraph.graph.message import add_messages from langchain_openai import ChatOpenAI from langchain_core.messages import HumanMessage, AIMessage
class AgentState(TypedDict): messages: Annotated[list, add_messages] task: str plan: list[str] current_step: int result: str
def create_langgraph_agent(): """Create a LangGraph plan-and-execute agent.""" llm = ChatOpenAI(model="gpt-4o")
def planner(state: AgentState) -> AgentState: task = state["task"] response = llm.invoke([ HumanMessage(content=f"Create a 3-step plan for: {task}\nReturn each step on a new line, numbered 1-3.") ]) plan = [line.strip() for line in response.content.split("\n") if line.strip()] return {**state, "plan": plan, "current_step": 0}
def executor(state: AgentState) -> AgentState: step = state["plan"][state["current_step"]] response = llm.invoke([HumanMessage(content=f"Execute this step: {step}")]) state["messages"].append(AIMessage(content=response.content)) return {**state, "current_step": state["current_step"] + 1}
def should_continue(state: AgentState) -> str: if state["current_step"] >= len(state["plan"]): return "summarize" return "execute"
def summarizer(state: AgentState) -> AgentState: messages = "\n".join([m.content for m in state["messages"]]) response = llm.invoke([ HumanMessage(content=f"Summarize these results:\n{messages}\nOriginal task: {state['task']}") ]) return {**state, "result": response.content}
graph = StateGraph(AgentState) graph.add_node("planner", planner) graph.add_node("executor", executor) graph.add_node("summarizer", summarizer) graph.set_entry_point("planner") graph.add_edge("planner", "executor") graph.add_conditional_edges("executor", should_continue, {"execute": "executor", "summarize": "summarizer"}) graph.add_edge("summarizer", END) return graph.compile()
